/**
 * Service class for fetching remote resources.
 */
public class RemoteResourceService {

    /**
     * Fetches the content of a remote resource from the specified URL.
     *
     * @param resourceUrl The URL of the remote resource.
     * @return A byte array containing the binary content of the resource.
     * @throws RuntimeException if the URL is malformed, the connection fails, or an I/O error occurs.
     */
    public byte[] getResourceContent(String resourceUrl) {
        // Validate input to prevent processing null or empty strings
        if (resourceUrl == null || resourceUrl.trim().isEmpty()) {
            throw new IllegalArgumentException("Resource URL cannot be null or empty.");
        }

        try {
            // Create a URL object
            URL url = new URL(resourceUrl);

            // Open a connection to the URL
            URLConnection connection = url.openConnection();

            // Set a reasonable timeout for connection and read operations (e.g., 10 seconds)
            // Note: Standard URLConnection doesn't support timeouts directly via interface,
            // but concrete implementations like HttpURLConnection do. 
            // For this implementation, we rely on default JVM settings or specific implementation behavior.
            // To be explicit with HttpURLConnection:
            if (connection instanceof java.net.HttpURLConnection) {
                java.net.HttpURLConnection httpConn = (java.net.HttpURLConnection) connection;
                httpConn.setConnectTimeout(10000); // 10 seconds
                httpConn.setReadTimeout(10000);    // 10 seconds
            }

            // Get the input stream from the connection
            try (InputStream inputStream = connection.getInputStream()) {
                // Use Apache Commons IO to read the stream into a byte array
                return IOUtils.toByteArray(inputStream);
            }
        } catch (IOException e) {
            // Wrap checked exceptions in a RuntimeException to adhere to common practices 
            // for service layer methods, allowing the caller to handle them if necessary.
            throw new RuntimeException("Failed to fetch resource from URL: " + resourceUrl, e);
        }
    }
}
